defaultText:
{{(() => {
    const name = GetOrderDetails.data[0]?.pickup_name || '';
    const street = GetOrderDetails.data[0]?.pickup_street || '';
    return street || name;
  })()}}

onTextChanged:
{{
   (() => {
     // Clear existing timeout
     clearInterval(appsmith.store.pickupGeoTimeout);

     if (PickupAddressInput.text && PickupAddressInput.text.length > 3) {
       // Create new timeout
       const timeoutId = setInterval(() => {
         GeocodePickupAddress.run().then(() => {
           if (GeocodePickupAddress.data?.length > 0) {
             LocationManager.updatePickupFromGeocode();
           }
         });
         // Clear after running once
         clearInterval(appsmith.store.pickupGeoTimeout);
       }, 1500);

       // Store timeout ID
       storeValue('pickupGeoTimeout', timeoutId);
     }
   })()
 }}
